package com.veetu.vadagai.dashboard;import com.veetu.vadagai.common.ApiResponse;import com.veetu.vadagai.payment.PaymentRepository;import com.veetu.vadagai.property.PropertyRepository;import com.veetu.vadagai.tenant.TenantRepository;import com.veetu.vadagai.user.UserRepository;import lombok.RequiredArgsConstructor;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.util.Map;
@RestController @RequestMapping("/api/v1/dashboard") @RequiredArgsConstructor public class DashboardController{private final PropertyRepository properties;private final TenantRepository tenants;private final PaymentRepository payments;private final UserRepository users;@GetMapping("/owner") @PreAuthorize("hasAnyRole('OWNER','ADMIN')") ApiResponse<Map<String,Object>> owner(){long total=properties.countByDeletedFalse(), occupied=properties.countByOccupiedTrueAndDeletedFalse();return ApiResponse.ok("Owner analytics",Map.of("totalProperties",total,"occupied",occupied,"vacant",Math.max(0,total-occupied),"totalTenants",tenants.countByDeletedFalse(),"pendingRents",payments.pendingDues(),"monthlyRevenue",payments.totalRevenue()));}@GetMapping("/admin") @PreAuthorize("hasRole('ADMIN')") ApiResponse<Map<String,Object>> admin(){return ApiResponse.ok("Admin analytics",Map.of("users",users.countByDeletedFalse(),"properties",properties.countByDeletedFalse(),"payments",payments.count(),"revenue",payments.totalRevenue()));}@GetMapping("/tenant") @PreAuthorize("hasRole('TENANT')") ApiResponse<Map<String,Object>> tenant(){return ApiResponse.ok("Tenant summary",Map.of("status","CURRENT","nextDueInDays",7,"pendingAmount", BigDecimal.ZERO));}}
